import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment, fetchStyleTemplate, saveStyleTemplate, checkTemplateDeletionImpact, purgeDeletedLabels, deleteTemplateSection } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment, StyleTemplate } from '../types';
import { 
  Library, Search, Plus, Trash2, Copy, Printer, ChevronDown, ChevronRight, X, Upload, FileText, Image as ImageIcon, Save, Loader2, Split, Grid2X2, AlertCircle, Download, MoreVertical, Layers, Users, Settings2, GripVertical, Table as TableIcon, List as ListIcon, LayoutPanelTop
} from 'lucide-react';

const COMMON_PRODUCT_TYPES = ['T-shirt', 'Pant', 'Shorts', 'Shirt', 'Innerwear', 'Sweatshirt', 'Hoodie'];

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [template, setTemplate] = useState<StyleTemplate[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal States
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isFormatEditorOpen, setIsFormatEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  // Format Editor Local State
  const [localTemplate, setLocalTemplate] = useState<StyleTemplate[]>([]);

  // Custom Product Type handling
  const [showNewTypeInput, setShowNewTypeInput] = useState(false);
  const [customProductType, setCustomProductType] = useState('');

  const loadData = async () => {
    setLoading(true);
    try {
        const [libData, tempData] = await Promise.all([
            fetchStyleLibrary(),
            fetchStyleTemplate()
        ]);
        // COMPLETELY ISOLATE 'General Info' from dynamic template logic
        const filteredTemplate = tempData.filter(t => t.section !== 'General Info');
        setStyles(libData);
        setTemplate(filteredTemplate);
    } catch (e) {
        console.error("Style Database Load Failed:", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const prepareDetailsForStyle = (styleDetails: StyleDetail[] = []) => {
      const merged: StyleDetail[] = [];
      template.forEach(t => {
          t.labels.forEach((label, idx) => {
              const existing = styleDetails.find(d => d.section === t.section && d.label === label);
              const isTable = t.is_table_flags?.[idx] || false;

              let content = existing?.content_text || '';
              if (isTable && (!content || content === '')) {
                  content = JSON.stringify([['', '']]);
              }

              merged.push(existing || { section: t.section, label, content_text: content, attachments: [] });
          });
      });
      return merged;
  };

  const handleOpenCreate = () => {
    setEditingStyle({ 
        style_no: '', style_text: '', category: 'Casuals', product_type: 'T-shirt', target_audience: 'Men', pcs_per_box: 1, packing_type: 'cover' 
    });
    setDetails(prepareDetailsForStyle([]));
    setIsEditorOpen(true);
    setShowNewTypeInput(false);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(prepareDetailsForStyle(style.details));
    setIsEditorOpen(true);
    setShowNewTypeInput(!COMMON_PRODUCT_TYPES.includes(style.product_type));
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d, id: undefined, style_id: undefined
    })) || [];
    setDetails(prepareDetailsForStyle(copiedDetails));
    setIsCopying(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const updated = [...details];
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name, url, type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    try {
        const finalStyle = { ...editingStyle, product_type: showNewTypeInput ? customProductType : editingStyle.product_type };
        const result = await upsertStyle(finalStyle, details);
        if (result.error) alert(`Save failed: ${result.error}`);
        else { setIsEditorOpen(false); await loadData(); }
    } catch(e: any) {
        alert(`Error: ${e.message}`);
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleDelete = async (styleId: string) => {
    if (!styleId) return;
    if (!confirm("Are you ABSOLUTELY sure? Deleting this Master Style will erase all technical data, tables, and images for this style number. This cannot be undone.")) return;

    setLoading(true);
    try {
        const result = await deleteStyle(styleId);
        if (result.success) {
            await loadData();
            setExpandedStyles(prev => prev.filter(id => id !== styleId));
        } else {
            alert(`Could not delete style: ${result.error}`);
        }
    } catch (e: any) {
        alert(`Deletion Error: ${e.message}`);
    } finally {
        setLoading(false);
    }
  };

  // --- FORMAT EDITOR LOGIC ---
  const handleOpenFormatEditor = () => {
      setLocalTemplate(JSON.parse(JSON.stringify(template)));
      setIsFormatEditorOpen(true);
  };

  const addSectionToTemplate = () => {
      const name = prompt("Enter Section Name (e.g., Fabric Specifications):");
      if (!name) return;
      if (localTemplate.some(t => t.section === name)) return alert("Section already exists.");
      setLocalTemplate([...localTemplate, { id: Date.now().toString(), section: name, labels: [], is_table_flags: [], display_order: localTemplate.length + 1 }]);
  };

  const removeSectionFromTemplate = async (sIdx: number) => {
      const section = localTemplate[sIdx].section;
      if (!confirm(`Delete ENTIRE section "${section}"? This will remove all its fields from all styles upon save.`)) return;

      const updated = [...localTemplate];
      updated.splice(sIdx, 1);
      setLocalTemplate(updated);
  };

  const addLabelToTemplate = (sectionIndex: number) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels.push('New Specification Field');
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      } else {
          updated[sectionIndex].is_table_flags.push(false);
      }
      setLocalTemplate(updated);
  };

  const updateLabelInTemplate = (sectionIndex: number, labelIndex: number, val: string) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels[labelIndex] = val;
      setLocalTemplate(updated);
  };

  const toggleTableFlag = (sectionIndex: number, labelIndex: number) => {
      const updated = [...localTemplate];
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      }
      updated[sectionIndex].is_table_flags[labelIndex] = !updated[sectionIndex].is_table_flags[labelIndex];
      setLocalTemplate(updated);
  };

  const removeLabelFromTemplate = (sectionIndex: number, labelIndex: number) => {
      const label = localTemplate[sectionIndex].labels[labelIndex];
      if (!confirm(`Remove field "${label}"? This is permanent.`)) return;
      const updated = [...localTemplate];
      updated[sectionIndex].labels.splice(labelIndex, 1);
      if (updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags.splice(labelIndex, 1);
      }
      setLocalTemplate(updated);
  };

  const handleSaveTemplate = async () => {
      setIsSubmitting(true);
      try {
          const originalSections = template.map(t => t.section);
          const currentSections = localTemplate.map(t => t.section);
          const removedSections = originalSections.filter(s => !currentSections.includes(s));

          for (const rs of removedSections) {
              await deleteTemplateSection(rs);
          }

          for (const section of localTemplate) {
              const oldSection = template.find(t => t.section === section.section);
              if (oldSection) {
                  const deletedLabels = oldSection.labels.filter(l => !section.labels.includes(l));
                  if (deletedLabels.length > 0) {
                      const impact = await checkTemplateDeletionImpact(section.section, section.labels);
                      if (impact.length > 0) {
                          const confirmDelete = confirm(`WARNING: Removing fields in "${section.section}" will delete data for styles:\n\n${impact.join('\n')}\n\nContinue?`);
                          if (!confirmDelete) { setIsSubmitting(false); return; }
                          await purgeDeletedLabels(section.section, section.labels);
                      }
                  }
              }
          }

          const result = await saveStyleTemplate(localTemplate);
          if (!result.success) {
            alert(`Template Save Error: ${result.error}`);
          } else {
            setIsFormatEditorOpen(false);
            await loadData();
          }
      } catch (e: any) {
          alert(`Template Save Exception: ${e.message}`);
      } finally {
          setIsSubmitting(false);
      }
  };

  const renderContent = (content: string, isTable: boolean) => {
      if (isTable) {
          try {
              const data = JSON.parse(content) as string[][];
              return (
                <table className="w-full text-xs mt-2 border border-slate-100">
                    <tbody className="divide-y divide-slate-100">
                        {data.map((row, idx) => (
                            <tr key={idx} className="divide-x divide-slate-100">
                                <td className="p-1 font-bold bg-slate-50 w-1/3">{row[0]}</td>
                                <td className="p-1">{row[1]}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
              );
          } catch(e) { return <span className="italic text-red-400 text-[10px]">Empty or Invalid Table Data</span>; }
      }
      return <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{content || '---'}</div>;
  };

  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;
    const sectionsHtml = template.map(t => {
      const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
      if (sectionDetails.length === 0) return '';
      return `
        <div class="print-section">
          <h2 class="section-title">${t.section}</h2>
          <div class="details-grid">
            ${t.labels.map((label, idx) => {
                const d = sectionDetails.find(sd => sd.label === label);
                const isTable = t.is_table_flags?.[idx];
                let contentHtml = d?.content_text || '---';
                if (isTable && d?.content_text) {
                    try {
                        const rows = JSON.parse(d.content_text) as string[][];
                        contentHtml = `<table style="width:100%; border-collapse:collapse; margin-top:5px;">${rows.map(r => `<tr><td style="border:1px solid #ddd; padding:5px; font-weight:bold; background:#f9f9f9; width:30%;">${r[0]}</td><td style="border:1px solid #ddd; padding:5px;">${r[1]}</td></tr>`).join('')}</table>`;
                    } catch(e) { contentHtml = '---'; }
                }
                return `
                  <div class="detail-box">
                    <div class="detail-label">${label}</div>
                    <div class="detail-content">${contentHtml}</div>
                    ${d?.attachments && d.attachments.length > 0 ? `<div class="attachment-gallery">${d.attachments.map(a => a.type === 'image' ? `<div class="img-container"><img src="${a.url}" /><div class="img-name">${a.name}</div></div>` : `<div class="doc-link">📄 ${a.name}</div>`).join('')}</div>` : ''}
                  </div>`;
            }).join('')}
          </div>
        </div>`;
    }).join('');
    win.document.write(`<html><head><title>${style.style_no}</title><style>@media print { body { -webkit-print-color-adjust: exact; } } body { font-family: system-ui, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; } .header { border-bottom: 4px solid #1e293b; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; } .style-no { font-size: 32px; font-weight: 900; margin: 0; color: #4f46e5; line-height: 1; } .style-text { font-size: 16px; font-weight: 600; color: #64748b; margin-top: 4px; } .meta-badges { display: flex; gap: 8px; margin-top: 10px; } .badge { background: #f1f5f9; padding: 4px 10px; border-radius: 4px; font-size: 11px; font-weight: 800; text-transform: uppercase; color: #475569; border: 1px solid #e2e8f0; } .section-title { background: #f1f5f9; padding: 10px 15px; border-left: 5px solid #4f46e5; margin: 40px 0 20px 0; font-size: 20px; font-weight: 800; text-transform: uppercase; } .detail-box { margin-bottom: 25px; border: 1px solid #e2e8f0; padding: 20px; border-radius: 8px; page-break-inside: avoid; } .detail-label { font-weight: 900; font-size: 14px; text-transform: uppercase; color: #475569; border-bottom: 1px solid #f1f5f9; padding-bottom: 5px; margin-bottom: 10px; } .detail-content { font-size: 16px; color: #0f172a; white-space: pre-wrap; } .attachment-gallery { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-top: 15px; } .img-container { border: 1px solid #ddd; padding: 5px; border-radius: 4px; text-align: center; } .img-container img { max-width: 100%; max-height: 400px; border-radius: 2px; } .img-name { font-size: 10px; color: #94a3b8; margin-top: 5px; } .doc-link { background: #f8fafc; padding: 8px; border-radius: 4px; font-size: 12px; font-weight: bold; border: 1px solid #e2e8f0; }</style></head><body><div class="header"><div><h1 class="style-no">STYLE: ${style.style_no}</h1><div class="style-text">${style.style_text || ''}</div><div class="meta-badges"><span class="badge">${style.category}</span><span class="badge">${style.product_type}</span><span class="badge">${style.target_audience}</span></div></div><div style="text-align: right; font-size: 12px; color: #64748b;">Printed: ${new Date().toLocaleString()}</div></div>${sectionsHtml}</body></html>`);
    win.document.close();
    setTimeout(() => { win.print(); }, 1000);
  };

  const filteredStyles = styles.filter(s => 
    s.style_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.product_type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg">
              <Library size={28}/> 
            </div>
            Style Lab <span className="text-slate-300 font-light mx-2">/</span> Master Database
          </h2>
          <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mt-1">Unified Technical Specifications Repository</p>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={handleOpenFormatEditor} className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl text-sm font-black hover:bg-slate-50 transition-all shadow-sm">
            <Settings2 size={18} className="text-indigo-600"/> Edit Format
          </button>
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setView('library')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'library' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid2X2 size={18}/> Library</button>
            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
          <button onClick={handleOpenCreate} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 flex items-center gap-2 hover:bg-indigo-700 active:scale-95 transition-all">
            <Plus size={20}/> Add Master Style
          </button>
        </div>
      </div>

      <div className="relative max-w-xl">
        <input 
          type="text" 
          placeholder="Search by Style No, Text or Type..." 
          className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-lg font-medium shadow-sm transition-all bg-white text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <Search className="absolute left-4 top-4.5 text-slate-400" size={24}/>
      </div>

      {view === 'library' && (
        <div className="space-y-4 animate-fade-in">
          {loading ? (
            <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest flex flex-col items-center gap-4">
              <Loader2 className="animate-spin text-indigo-600" size={48}/>
              Scanning Library...
            </div>
          ) : filteredStyles.length === 0 ? (
            <div className="p-20 bg-white rounded-3xl border border-slate-200 text-center">
              <AlertCircle size={64} className="mx-auto text-slate-200 mb-4"/>
              <p className="text-xl font-black text-slate-400">No Master Styles Found.</p>
            </div>
          ) : (
            filteredStyles.map(style => {
              const isExpanded = expandedStyles.includes(style.id);
              return (
                <div key={style.id} className={`bg-white rounded-3xl border shadow-sm transition-all overflow-hidden ${isExpanded ? 'border-indigo-400 shadow-xl ring-4 ring-indigo-500/5' : 'border-slate-200 hover:border-indigo-300'}`}>
                  <div className={`p-6 flex items-center justify-between cursor-pointer transition-colors ${isExpanded ? 'bg-indigo-50' : 'hover:bg-slate-50'}`} onClick={() => toggleExpand(style.id)}>
                    <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-white rounded-2xl border-2 border-indigo-100 flex items-center justify-center font-black text-indigo-600 text-xl shadow-inner">
                        {style.style_no.slice(0,2).toUpperCase()}
                      </div>
                      <div>
                        <div className="flex items-baseline gap-2">
                            <h3 className="text-2xl font-black text-slate-800">{style.style_no}</h3>
                            <span className="text-sm font-bold text-slate-400 italic">{style.style_text}</span>
                        </div>
                        <div className="flex items-center gap-3 mt-1.5">
                          <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2.5 py-1 rounded-md">{style.category}</span>
                          <span className="text-[9px] font-black uppercase tracking-widest bg-slate-100 text-slate-700 px-2.5 py-1 rounded-md">{style.product_type}</span>
                          <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-600 text-white px-2.5 py-1 rounded-md">{style.target_audience}</span>
                          <span className="text-xs font-bold text-slate-400 tracking-tight ml-2">Packing: {style.packing_type} &bull; {style.pcs_per_box} pcs/box</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); handlePrintStyle(style); }} className="p-3 bg-white text-slate-400 hover:text-indigo-600 rounded-xl border border-slate-200 hover:border-indigo-200 transition-all shadow-sm" title="Print specs"><Printer size={20}/></button>
                      <button onClick={(e) => { e.stopPropagation(); handleEdit(style); }} className="p-3 bg-white text-slate-400 hover:text-blue-600 rounded-xl border border-slate-200 hover:border-blue-200 transition-all shadow-sm" title="Edit style"><ImageIcon size={20}/></button>
                      <div className={`p-2 rounded-full transition-transform duration-300 ${isExpanded ? 'rotate-180 bg-indigo-600 text-white' : 'text-slate-300'}`}>
                        <ChevronDown size={24}/>
                      </div>
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="p-8 bg-white border-t border-indigo-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 animate-fade-in">
                      {template.map(t => {
                        const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
                        return (
                          <div key={t.section} className="space-y-4">
                            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 border-b border-slate-100 pb-2">{t.section}</h4>
                            <div className="space-y-6">
                              {t.labels.map((label, lIdx) => {
                                  const d = sectionDetails.find(sd => sd.label === label);
                                  const isTable = t.is_table_flags?.[lIdx];
                                  return (
                                    <div key={label}>
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-tight mb-1 flex items-center gap-2">
                                        {label}
                                        {isTable && <TableIcon size={12} className="opacity-40"/>}
                                      </div>
                                      {renderContent(d?.content_text || '', isTable)}
                                      {d?.attachments && d.attachments.length > 0 && (
                                        <div className="flex gap-2 mt-3 flex-wrap">
                                          {d.attachments.map((a, i) => (
                                            <a key={i} href={a.url} target="_blank" rel="noreferrer" className="w-10 h-10 rounded-lg border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-200 transition-all" title={a.name}>
                                              {a.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>}
                                            </a>
                                          ))}
                                        </div>
                                      )}
                                    </div>
                                  );
                              })}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

      {view === 'comparison' && (
        <div className="flex gap-6 animate-fade-in overflow-x-auto pb-10 min-h-[600px] items-start scrollbar-hide">
          <div className="w-80 shrink-0 bg-white rounded-3xl border border-slate-200 p-6 space-y-4 sticky left-0 shadow-xl shadow-slate-200/50">
             <h3 className="font-black text-slate-700 uppercase tracking-widest text-xs flex items-center gap-2">
                <Search size={14}/> Add Styles to Compare
             </h3>
             <div className="space-y-2">
                {styles.map(s => {
                  const isSelected = selectedForCompare.includes(s.id);
                  return (
                    <button 
                      key={s.id} 
                      onClick={() => setSelectedForCompare(prev => isSelected ? prev.filter(i => i !== s.id) : [...prev, s.id])}
                      className={`w-full p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${isSelected ? 'border-indigo-600 bg-indigo-50 shadow-md' : 'border-slate-50 hover:border-indigo-200 bg-slate-50'}`}
                    >
                      <div>
                        <div className={`font-black text-lg ${isSelected ? 'text-indigo-900' : 'text-slate-700'}`}>{s.style_no}</div>
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{s.category} • {s.product_type}</div>
                      </div>
                      <div className={`p-1.5 rounded-full transition-all ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600'}`}>
                        {isSelected ? <X size={14}/> : <Plus size={14}/>}
                      </div>
                    </button>
                  );
                })}
             </div>
          </div>

          <div className="flex gap-6">
            {selectedForCompare.map(styleId => {
              const style = styles.find(s => s.id === styleId);
              if (!style) return null;
              return (
