                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Description Text</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" value={editingStyle.style_text} onChange={e => setEditingStyle({...editingStyle, style_text: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.category} onChange={e => setEditingStyle({...editingStyle, category: e.target.value as any})}><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Audience</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.target_audience} onChange={e => setEditingStyle({...editingStyle, target_audience: e.target.value as any})}><option value="Men">Men</option><option value="Boys">Boys</option></select></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex justify-between">Product Type <button onClick={() => setShowNewTypeInput(!showNewTypeInput)} className="text-indigo-600 hover:underline">{showNewTypeInput ? 'Standard' : 'Custom'}</button></label>{showNewTypeInput ? (<input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={customProductType} onChange={e => setCustomProductType(e.target.value)}/>) : (<select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.product_type} onChange={e => setEditingStyle({...editingStyle, product_type: e.target.value})}>{COMMON_PRODUCT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}</select>)}</div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Packing</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.packing_type} onChange={e => setEditingStyle({...editingStyle, packing_type: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Pcs / Box</label><input type="number" className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.pcs_per_box} onChange={e => setEditingStyle({...editingStyle, pcs_per_box: parseInt(e.target.value) || 1})}/></div>
                  </div>

                  <div className="space-y-16">
                    {template.map(sec => (
                         <div key={sec.section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3"><h4 className="text-xl font-black text-slate-800 uppercase tracking-tight">{sec.section}</h4></div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {template.find(t => t.section === sec.section)?.labels.map((label, lIdx) => {
                                 const globalIdx = details.findIndex(gd => gd.section === sec.section && gd.label === label);
                                 const d = details[globalIdx];
                                 const isTable = sec.is_table_flags?.[lIdx];

                                 return (
                                   <div key={label} className="group bg-slate-50/50 p-6 rounded-[30px] border border-transparent hover:border-indigo-100 hover:bg-white transition-all space-y-4">
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center justify-between">
                                        {label}
                                        {isTable && <TableIcon size={14} className="opacity-50"/>}
                                      </div>

                                      {isTable ? (
                                        <div className="space-y-2">
                                          {(() => {
                                            let tableData: string[][] = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) { }
                                            return tableData.map((row, rowIdx) => (
                                              <div key={rowIdx} className="flex gap-2 animate-fade-in">
                                                <input className="w-1/3 border border-slate-200 rounded-xl p-3 text-xs font-bold bg-white" placeholder="Key" value={row[0]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][0] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <input className="flex-1 border border-slate-200 rounded-xl p-3 text-xs bg-white" placeholder="Value" value={row[1]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][1] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <button onClick={() => {
                                                  if (tableData.length === 1) return;
                                                  const newTable = tableData.filter((_, i) => i !== rowIdx);
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }} className="p-2 text-slate-300 hover:text-red-500"><X size={14}/></button>
                                              </div>
                                            ));
                                          })()}
                                          <button onClick={() => {
                                            let tableData = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) {}
                                            const updated = [...details];
                                            updated[globalIdx].content_text = JSON.stringify([...tableData, ['', '']]);
                                            setDetails(updated);
                                          }} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100">+ Add Row Entry</button>
                                        </div>
                                      ) : (
                                        <textarea className="w-full border-2 border-slate-100 rounded-3xl p-6 text-sm h-32 bg-white text-slate-800 font-medium focus:border-indigo-400 outline-none transition-all resize-none shadow-inner" placeholder={`Provide technical specifications for ${label}...`} value={d.content_text} onChange={e => { const updated = [...details]; updated[globalIdx].content_text = e.target.value; setDetails(updated); }}/>
                                      )}

                                      <div className="flex gap-2 flex-wrap pt-2">
                                        {d.attachments.map((a, aIdx) => (
                                            <div key={aIdx} className="group/att relative w-16 h-16 rounded-2xl border border-slate-200 bg-white flex items-center justify-center shadow-sm overflow-hidden">
                                                {a.type === 'image' ? <img src={a.url} className="w-full h-full object-cover"/> : <FileText size={24} className="text-slate-400"/>}
                                                <button onClick={() => { const updated = [...details]; updated[globalIdx].attachments.splice(aIdx, 1); setDetails(updated); }} className="absolute inset-0 bg-red-600/80 text-white opacity-0 group-hover/att:opacity-100 flex items-center justify-center transition-opacity"><Trash2 size={20}/></button>
                                            </div>
                                        ))}
                                        <label className="w-16 h-16 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-400 cursor-pointer transition-all">
                                            <Upload size={20}/><input type="file" multiple className="hidden" onChange={e => handleFileUpload(e, globalIdx)}/>
                                        </label>
                                      </div>
                                   </div>);
                               })}
                            </div>
                         </div>
                    ))}
                  </div>
               </div>
            </div>

            <div className="p-8 border-t bg-slate-50 flex justify-end gap-4 shadow-[0_-10px_20px_rgba(0,0,0,0.03)]">
               <button onClick={() => setIsEditorOpen(false)} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs">Discard</button>
               <button onClick={handleSave} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">{isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Transmitting...</> : <><Save size={20}/> Save Master Style</>}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment, fetchStyleTemplate, saveStyleTemplate, checkTemplateDeletionImpact, purgeDeletedLabels, deleteTemplateSection } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment, StyleTemplate } from '../types';
import { 
  Library, Search, Plus, Trash2, Copy, Printer, ChevronDown, ChevronRight, X, Upload, FileText, Image as ImageIcon, Save, Loader2, Split, Grid2X2, AlertCircle, Download, MoreVertical, Layers, Users, Settings2, GripVertical, Table as TableIcon, List as ListIcon, LayoutPanelTop
} from 'lucide-react';

const COMMON_PRODUCT_TYPES = ['T-shirt', 'Pant', 'Shorts', 'Shirt', 'Innerwear', 'Sweatshirt', 'Hoodie'];

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [template, setTemplate] = useState<StyleTemplate[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal States
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isFormatEditorOpen, setIsFormatEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  // Format Editor Local State
  const [localTemplate, setLocalTemplate] = useState<StyleTemplate[]>([]);

  // Custom Product Type handling
  const [showNewTypeInput, setShowNewTypeInput] = useState(false);
  const [customProductType, setCustomProductType] = useState('');

  const loadData = async () => {
    setLoading(true);
    try {
        const [libData, tempData] = await Promise.all([
            fetchStyleLibrary(),
            fetchStyleTemplate()
        ]);
        // COMPLETELY ISOLATE 'General Info' from dynamic template logic
        const filteredTemplate = tempData.filter(t => t.section !== 'General Info');
        setStyles(libData);
        setTemplate(filteredTemplate);
    } catch (e) {
        console.error("Style Database Load Failed:", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const prepareDetailsForStyle = (styleDetails: StyleDetail[] = []) => {
      const merged: StyleDetail[] = [];
      template.forEach(t => {
          t.labels.forEach((label, idx) => {
              const existing = styleDetails.find(d => d.section === t.section && d.label === label);
              const isTable = t.is_table_flags?.[idx] || false;

              let content = existing?.content_text || '';
              if (isTable && (!content || content === '')) {
                  content = JSON.stringify([['', '']]);
              }

              merged.push(existing || { section: t.section, label, content_text: content, attachments: [] });
          });
      });
      return merged;
  };

  const handleOpenCreate = () => {
    setEditingStyle({ 
        style_no: '', style_text: '', category: 'Casuals', product_type: 'T-shirt', target_audience: 'Men', pcs_per_box: 1, packing_type: 'cover' 
    });
    setDetails(prepareDetailsForStyle([]));
    setIsEditorOpen(true);
    setShowNewTypeInput(false);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(prepareDetailsForStyle(style.details));
    setIsEditorOpen(true);
    setShowNewTypeInput(!COMMON_PRODUCT_TYPES.includes(style.product_type));
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d, id: undefined, style_id: undefined
    })) || [];
    setDetails(prepareDetailsForStyle(copiedDetails));
    setIsCopying(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const updated = [...details];
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name, url, type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    try {
        const finalStyle = { ...editingStyle, product_type: showNewTypeInput ? customProductType : editingStyle.product_type };
        const result = await upsertStyle(finalStyle, details);
        if (result.error) alert(`Save failed: ${result.error}`);
        else { setIsEditorOpen(false); await loadData(); }
    } catch(e: any) {
        alert(`Error: ${e.message}`);
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleDelete = async (styleId: string) => {
    if (!styleId) return;
    if (!confirm("Are you ABSOLUTELY sure? Deleting this Master Style will erase all technical data, tables, and images for this style number. This cannot be undone.")) return;

    setLoading(true);
    try {
        const result = await deleteStyle(styleId);
        if (result.success) {
            await loadData();
            setExpandedStyles(prev => prev.filter(id => id !== styleId));
        } else {
            alert(`Could not delete style: ${result.error}`);
        }
    } catch (e: any) {
        alert(`Deletion Error: ${e.message}`);
    } finally {
        setLoading(false);
    }
  };

  // --- FORMAT EDITOR LOGIC ---
  const handleOpenFormatEditor = () => {
      setLocalTemplate(JSON.parse(JSON.stringify(template)));
      setIsFormatEditorOpen(true);
  };

  const addSectionToTemplate = () => {
      const name = prompt("Enter Section Name (e.g., Fabric Specifications):");
      if (!name) return;
      if (localTemplate.some(t => t.section === name)) return alert("Section already exists.");
      setLocalTemplate([...localTemplate, { id: Date.now().toString(), section: name, labels: [], is_table_flags: [], display_order: localTemplate.length + 1 }]);
  };

  const removeSectionFromTemplate = async (sIdx: number) => {
      const section = localTemplate[sIdx].section;
      if (!confirm(`Delete ENTIRE section "${section}"? This will remove all its fields from all styles upon save.`)) return;

      const updated = [...localTemplate];
      updated.splice(sIdx, 1);
      setLocalTemplate(updated);
  };

  const addLabelToTemplate = (sectionIndex: number) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels.push('New Specification Field');
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      } else {
          updated[sectionIndex].is_table_flags.push(false);
      }
      setLocalTemplate(updated);
  };

  const updateLabelInTemplate = (sectionIndex: number, labelIndex: number, val: string) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels[labelIndex] = val;
      setLocalTemplate(updated);
  };

  const toggleTableFlag = (sectionIndex: number, labelIndex: number) => {
      const updated = [...localTemplate];
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      }
      updated[sectionIndex].is_table_flags[labelIndex] = !updated[sectionIndex].is_table_flags[labelIndex];
      setLocalTemplate(updated);
  };

  const removeLabelFromTemplate = (sectionIndex: number, labelIndex: number) => {
      const label = localTemplate[sectionIndex].labels[labelIndex];
      if (!confirm(`Remove field "${label}"? This is permanent.`)) return;
      const updated = [...localTemplate];
      updated[sectionIndex].labels.splice(labelIndex, 1);
      if (updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags.splice(labelIndex, 1);
      }
      setLocalTemplate(updated);
  };

  const handleSaveTemplate = async () => {
      setIsSubmitting(true);
      try {
          const originalSections = template.map(t => t.section);
          const currentSections = localTemplate.map(t => t.section);
          const removedSections = originalSections.filter(s => !currentSections.includes(s));

          for (const rs of removedSections) {
              await deleteTemplateSection(rs);
          }

          for (const section of localTemplate) {
              const oldSection = template.find(t => t.section === section.section);
              if (oldSection) {
                  const deletedLabels = oldSection.labels.filter(l => !section.labels.includes(l));
                  if (deletedLabels.length > 0) {
                      const impact = await checkTemplateDeletionImpact(section.section, section.labels);
                      if (impact.length > 0) {
                          const confirmDelete = confirm(`WARNING: Removing fields in "${section.section}" will delete data for styles:\n\n${impact.join('\n')}\n\nContinue?`);
                          if (!confirmDelete) { setIsSubmitting(false); return; }
                          await purgeDeletedLabels(section.section, section.labels);
                      }
                  }
              }
          }

          const result = await saveStyleTemplate(localTemplate);
          if (!result.success) {
            alert(`Template Save Error: ${result.error}`);
          } else {
            setIsFormatEditorOpen(false);
            await loadData();
          }
      } catch (e: any) {
          alert(`Template Save Exception: ${e.message}`);
      } finally {
          setIsSubmitting(false);
      }
  };

  const renderContent = (content: string, isTable: boolean) => {
      if (isTable) {
          try {
              const data = JSON.parse(content) as string[][];
              return (
                <table className="w-full text-xs mt-2 border border-slate-100">
                    <tbody className="divide-y divide-slate-100">
                        {data.map((row, idx) => (
                            <tr key={idx} className="divide-x divide-slate-100">
                                <td className="p-1 font-bold bg-slate-50 w-1/3">{row[0]}</td>
                                <td className="p-1">{row[1]}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
              );
          } catch(e) { return <span className="italic text-red-400 text-[10px]">Empty or Invalid Table Data</span>; }
      }
      return <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{content || '---'}</div>;
  };

  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;
    const sectionsHtml = template.map(t => {
      const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
      if (sectionDetails.length === 0) return '';
      return `
        <div class="print-section">
          <h2 class="section-title">${t.section}</h2>
          <div class="details-grid">
            ${t.labels.map((label, idx) => {
                const d = sectionDetails.find(sd => sd.label === label);
                const isTable = t.is_table_flags?.[idx];
                let contentHtml = d?.content_text || '---';
                if (isTable && d?.content_text) {
                    try {
                        const rows = JSON.parse(d.content_text) as string[][];
                        contentHtml = `<table style="width:100%; border-collapse:collapse; margin-top:5px;">${rows.map(r => `<tr><td style="border:1px solid #ddd; padding:5px; font-weight:bold; background:#f9f9f9; width:30%;">${r[0]}</td><td style="border:1px solid #ddd; padding:5px;">${r[1]}</td></tr>`).join('')}</table>`;
                    } catch(e) { contentHtml = '---'; }
                }
                return `
                  <div class="detail-box">
                    <div class="detail-label">${label}</div>
                    <div class="detail-content">${contentHtml}</div>
                    ${d?.attachments && d.attachments.length > 0 ? `<div class="attachment-gallery">${d.attachments.map(a => a.type === 'image' ? `<div class="img-container"><img src="${a.url}" /><div class="img-name">${a.name}</div></div>` : `<div class="doc-link">📄 ${a.name}</div>`).join('')}</div>` : ''}
                  </div>`;
            }).join('')}
          </div>
        </div>`;
    }).join('');
    win.document.write(`<html><head><title>${style.style_no}</title><style>@media print { body { -webkit-print-color-adjust: exact; } } body { font-family: system-ui, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; } .header { border-bottom: 4px solid #1e293b; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; } .style-no { font-size: 32px; font-weight: 900; margin: 0; color: #4f46e5; line-height: 1; } .style-text { font-size: 16px; font-weight: 600; color: #64748b; margin-top: 4px; } .meta-badges { display: flex; gap: 8px; margin-top: 10px; } .badge { background: #f1f5f9; padding: 4px 10px; border-radius: 4px; font-size: 11px; font-weight: 800; text-transform: uppercase; color: #475569; border: 1px solid #e2e8f0; } .section-title { background: #f1f5f9; padding: 10px 15px; border-left: 5px solid #4f46e5; margin: 40px 0 20px 0; font-size: 20px; font-weight: 800; text-transform: uppercase; } .detail-box { margin-bottom: 25px; border: 1px solid #e2e8f0; padding: 20px; border-radius: 8px; page-break-inside: avoid; } .detail-label { font-weight: 900; font-size: 14px; text-transform: uppercase; color: #475569; border-bottom: 1px solid #f1f5f9; padding-bottom: 5px; margin-bottom: 10px; } .detail-content { font-size: 16px; color: #0f172a; white-space: pre-wrap; } .attachment-gallery { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-top: 15px; } .img-container { border: 1px solid #ddd; padding: 5px; border-radius: 4px; text-align: center; } .img-container img { max-width: 100%; max-height: 400px; border-radius: 2px; } .img-name { font-size: 10px; color: #94a3b8; margin-top: 5px; } .doc-link { background: #f8fafc; padding: 8px; border-radius: 4px; font-size: 12px; font-weight: bold; border: 1px solid #e2e8f0; }</style></head><body><div class="header"><div><h1 class="style-no">STYLE: ${style.style_no}</h1><div class="style-text">${style.style_text || ''}</div><div class="meta-badges"><span class="badge">${style.category}</span><span class="badge">${style.product_type}</span><span class="badge">${style.target_audience}</span></div></div><div style="text-align: right; font-size: 12px; color: #64748b;">Printed: ${new Date().toLocaleString()}</div></div>${sectionsHtml}</body></html>`);
    win.document.close();
    setTimeout(() => { win.print(); }, 1000);
  };

  const filteredStyles = styles.filter(s => 
    s.style_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.product_type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg">
              <Library size={28}/> 
            </div>
            Style Lab <span className="text-slate-300 font-light mx-2">/</span> Master Database
          </h2>
          <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mt-1">Unified Technical Specifications Repository</p>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={handleOpenFormatEditor} className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl text-sm font-black hover:bg-slate-50 transition-all shadow-sm">
            <Settings2 size={18} className="text-indigo-600"/> Edit Format
          </button>
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setView('library')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'library' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid2X2 size={18}/> Library</button>
            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
          <button onClick={handleOpenCreate} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 flex items-center gap-2 hover:bg-indigo-700 active:scale-95 transition-all">
            <Plus size={20}/> Add Master Style
          </button>
        </div>
      </div>

      <div className="relative max-w-xl">
        <input 
          type="text" 
          placeholder="Search by Style No, Text or Type..." 
          className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-lg font-medium shadow-sm transition-all bg-white text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <Search className="absolute left-4 top-4.5 text-slate-400" size={24}/>
      </div>

      {view === 'library' && (
        <div className="space-y-4 animate-fade-in">
          {loading ? (
            <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest flex flex-col items-center gap-4">
              <Loader2 className="animate-spin text-indigo-600" size={48}/>
              Scanning Library...
            </div>
          ) : filteredStyles.length === 0 ? (
            <div className="p-20 bg-white rounded-3xl border border-slate-200 text-center">
              <AlertCircle size={64} className="mx-auto text-slate-200 mb-4"/>
              <p className="text-xl font-black text-slate-400">No Master Styles Found.</p>
            </div>
          ) : (
            filteredStyles.map(style => {
              const isExpanded = expandedStyles.includes(style.id);
              return (
                <div key={style.id} className={`bg-white rounded-3xl border shadow-sm transition-all overflow-hidden ${isExpanded ? 'border-indigo-400 shadow-xl ring-4 ring-indigo-500/5' : 'border-slate-200 hover:border-indigo-300'}`}>
                  <div className={`p-6 flex items-center justify-between cursor-pointer transition-colors ${isExpanded ? 'bg-indigo-50' : 'hover:bg-slate-50'}`} onClick={() => toggleExpand(style.id)}>
                    <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-white rounded-2xl border-2 border-indigo-100 flex items-center justify-center font-black text-indigo-600 text-xl shadow-inner">
                        {style.style_no.slice(0,2).toUpperCase()}
                      </div>
                      <div>
                        <div className="flex items-baseline gap-2">
                            <h3 className="text-2xl font-black text-slate-800">{style.style_no}</h3>
                            <span className="text-sm font-bold text-slate-400 italic">{style.style_text}</span>
                        </div>
                        <div className="flex items-center gap-3 mt-1.5">
                          <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2.5 py-1 rounded-md">{style.category}</span>
                          <span className="text-[9px] font-black uppercase tracking-widest bg-slate-100 text-slate-700 px-2.5 py-1 rounded-md">{style.product_type}</span>
                          <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-600 text-white px-2.5 py-1 rounded-md">{style.target_audience}</span>
                          <span className="text-xs font-bold text-slate-400 tracking-tight ml-2">Packing: {style.packing_type} &bull; {style.pcs_per_box} pcs/box</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); handlePrintStyle(style); }} className="p-3 bg-white text-slate-400 hover:text-indigo-600 rounded-xl border border-slate-200 hover:border-indigo-200 transition-all shadow-sm" title="Print specs"><Printer size={20}/></button>
                      <button onClick={(e) => { e.stopPropagation(); handleEdit(style); }} className="p-3 bg-white text-slate-400 hover:text-blue-600 rounded-xl border border-slate-200 hover:border-blue-200 transition-all shadow-sm" title="Edit style"><ImageIcon size={20}/></button>
                      <div className={`p-2 rounded-full transition-transform duration-300 ${isExpanded ? 'rotate-180 bg-indigo-600 text-white' : 'text-slate-300'}`}>
                        <ChevronDown size={24}/>
                      </div>
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="p-8 bg-white border-t border-indigo-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 animate-fade-in">
                      {template.map(t => {
                        const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
                        return (
                          <div key={t.section} className="space-y-4">
                            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 border-b border-slate-100 pb-2">{t.section}</h4>
                            <div className="space-y-6">
                              {t.labels.map((label, lIdx) => {
                                  const d = sectionDetails.find(sd => sd.label === label);
                                  const isTable = t.is_table_flags?.[lIdx];
                                  return (
                                    <div key={label}>
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-tight mb-1 flex items-center gap-2">
                                        {label}
                                        {isTable && <TableIcon size={12} className="opacity-40"/>}
                                      </div>
                                      {renderContent(d?.content_text || '', isTable)}
                                      {d?.attachments && d.attachments.length > 0 && (
                                        <div className="flex gap-2 mt-3 flex-wrap">
                                          {d.attachments.map((a, i) => (
                                            <a key={i} href={a.url} target="_blank" rel="noreferrer" className="w-10 h-10 rounded-lg border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-200 transition-all" title={a.name}>
                                              {a.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>}
                                            </a>
                                          ))}
                                        </div>
                                      )}
                                    </div>
                                  );
                              })}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

      {view === 'comparison' && (
        <div className="flex gap-6 animate-fade-in overflow-x-auto pb-10 min-h-[600px] items-start scrollbar-hide">
          <div className="w-80 shrink-0 bg-white rounded-3xl border border-slate-200 p-6 space-y-4 sticky left-0 shadow-xl shadow-slate-200/50">
             <h3 className="font-black text-slate-700 uppercase tracking-widest text-xs flex items-center gap-2">
                <Search size={14}/> Add Styles to Compare
             </h3>
             <div className="space-y-2">
                {styles.map(s => {
                  const isSelected = selectedForCompare.includes(s.id);
                  return (
                    <button 
                      key={s.id} 
                      onClick={() => setSelectedForCompare(prev => isSelected ? prev.filter(i => i !== s.id) : [...prev, s.id])}
                      className={`w-full p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${isSelected ? 'border-indigo-600 bg-indigo-50 shadow-md' : 'border-slate-50 hover:border-indigo-200 bg-slate-50'}`}
                    >
                      <div>
                        <div className={`font-black text-lg ${isSelected ? 'text-indigo-900' : 'text-slate-700'}`}>{s.style_no}</div>
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{s.category} • {s.product_type}</div>
                      </div>
                      <div className={`p-1.5 rounded-full transition-all ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600'}`}>
                        {isSelected ? <X size={14}/> : <Plus size={14}/>}
                      </div>
                    </button>
                  );
                })}
             </div>
          </div>

          <div className="flex gap-6">
            {selectedForCompare.map(styleId => {
              const style = styles.find(s => s.id === styleId);
              if (!style) return null;
              return (
                <div key={style.id} className="w-[450px] shrink-0 bg-white rounded-3xl border-2 border-indigo-100 shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-scale-up">
                   <div className="p-6 bg-indigo-600 text-white flex justify-between items-start">
                      <div>
                        <h4 className="text-3xl font-black tracking-tight">{style.style_no}</h4>
                        <div className="flex gap-2 mt-1">
                            <div className="text-[9px] font-black uppercase bg-white/20 px-2 py-1 rounded inline-block">{style.category}</div>
                            <div className="text-[9px] font-black uppercase bg-white/20 px-2 py-1 rounded inline-block">{style.product_type}</div>
                            <div className="text-[9px] font-black uppercase bg-white px-2 py-1 rounded inline-block text-indigo-700">{style.target_audience}</div>
                        </div>
                      </div>
                      <button onClick={() => setSelectedForCompare(prev => prev.filter(i => i !== style.id))} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24}/></button>
                   </div>
                   <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/30">
                      {template.map(t => {
                         const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
                         return (
                           <div key={t.section} className="space-y-4">
                              <h5 className="font-black text-indigo-400 text-[10px] uppercase tracking-widest border-b border-indigo-100 pb-2">{t.section}</h5>
                              <div className="space-y-4">
                                {t.labels.map((label, lIdx) => {
                                  const d = sectionDetails.find(sd => sd.label === label);
                                  const isTable = t.is_table_flags?.[lIdx];
                                  return (
                                    <div key={label} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                                       <div className="text-xs font-black text-slate-800 uppercase tracking-tight mb-2 flex items-center justify-between">
                                          {label}
                                          {d?.attachments && d.attachments.length > 0 && <span className="bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded text-[9px] uppercase font-black">{d.attachments.length} files</span>}
                                       </div>
                                       {renderContent(d?.content_text || '', isTable)}
                                       {d?.attachments && d.attachments.length > 0 && (
                                         <div className="grid grid-cols-2 gap-2 mt-4">
                                            {d.attachments.map((a, i) => (
                                              <a key={i} href={a.url} target="_blank" rel="noreferrer" className="block rounded-xl border border-slate-100 overflow-hidden hover:shadow-lg transition-all group relative">
                                                 {a.type === 'image' ? <img src={a.url} className="w-full h-32 object-cover transition-transform group-hover:scale-110"/> : <div className="w-full h-32 bg-slate-50 flex flex-col items-center justify-center text-slate-400 gap-2"><FileText size={32}/><span className="text-[10px] px-2 text-center truncate w-full font-bold">{a.name}</span></div>}
                                                 <div className="absolute inset-0 bg-indigo-600/60 opacity-0 group-hover:opacity-100 flex items-center justify-center text-white transition-opacity"><Download size={20}/></div>
                                              </a>))}
                                         </div>
                                       )}
                                    </div>
                                  );
                                })}
                              </div>
                           </div>
                         );
                      })}
                   </div>
                   <div className="p-4 border-t bg-slate-50 flex justify-between">
                      <button onClick={() => handlePrintStyle(style)} className="flex-1 flex items-center justify-center gap-2 font-black text-xs text-indigo-600 uppercase tracking-widest hover:bg-white py-3 rounded-xl transition-all"><Printer size={16}/> Full Print</button>
                   </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {isFormatEditorOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col max-h-[90vh] animate-scale-up border border-slate-200">
                <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
                    <div>
                        <h3 className="text-3xl font-black text-slate-800 tracking-tight">Technical Specification Blueprint</h3>
                        <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-1">Configure global fields and sections for all Styles</p>
                    </div>
                    <button onClick={() => setIsFormatEditorOpen(false)} className="text-slate-300 hover:text-slate-600 transition-colors p-2 hover:bg-slate-100 rounded-full"><X size={40}/></button>
                </div>

                <div className="flex-1 overflow-y-auto p-10 space-y-12 bg-slate-50/20">
                    {localTemplate.map((sec, sIdx) => (
                        <div key={sIdx} className="space-y-4 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative group/sec">
                            <div className="flex items-center justify-between border-b-2 border-indigo-100 pb-3">
                                <div className="flex items-center gap-4">
                                    <LayoutPanelTop size={24} className="text-indigo-600"/>
                                    <input 
                                        className="text-xl font-black text-slate-800 uppercase focus:ring-0 border-none bg-transparent p-0"
                                        value={sec.section}
                                        onChange={(e) => {
                                            const updated = [...localTemplate];
                                            updated[sIdx].section = e.target.value;
                                            setLocalTemplate(updated);
                                        }}
                                    />
                                </div>
                                <button onClick={() => removeSectionFromTemplate(sIdx)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all opacity-0 group-sec:opacity-100">
                                    <Trash2 size={20}/>
                                </button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
                                {sec.labels.map((label, lIdx) => (
                                    <div key={lIdx} className="flex flex-col gap-2 p-3 bg-slate-50 rounded-2xl border border-slate-100 shadow-inner group">
                                        <div className="flex items-center gap-2">
                                            <GripVertical size={16} className="text-slate-300 cursor-grab"/>
                                            <input 
                                                className="flex-1 bg-transparent border-none p-0 text-sm font-bold text-slate-700 focus:ring-0"
                                                value={label}
                                                // Fixed undefined variables sectionIndex and labelIndex by using sIdx and lIdx from the map scope
                                                onChange={(e) => updateLabelInTemplate(sIdx, lIdx, e.target.value)}
                                            />
                                            <button 
                                                onClick={() => toggleTableFlag(sIdx, lIdx)}
                                                className={`p-1.5 rounded-lg transition-all ${sec.is_table_flags?.[lIdx] ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-300 hover:bg-slate-200'}`}
                                                title="Toggle Table Mode"
                                            >
                                                <TableIcon size={14}/>
                                            </button>
                                            <button onClick={() => removeLabelFromTemplate(sIdx, lIdx)} className="p-1.5 text-slate-200 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all">
                                                <Trash2 size={14}/>
                                            </button>
                                        </div>
                                        {sec.is_table_flags?.[lIdx] && <span className="text-[9px] font-black text-indigo-500 uppercase flex items-center gap-1"><TableIcon size={8}/> Dynamic Table Mode</span>}
                                    </div>
                                ))}
                                <button 
                                    onClick={() => addLabelToTemplate(sIdx)}
                                    className="border-2 border-dashed border-slate-200 rounded-2xl p-3 text-slate-400 hover:border-indigo-400 hover:text-indigo-600 hover:bg-white transition-all flex items-center justify-center gap-2 text-xs font-black uppercase"
                                >
                                    <Plus size={16}/> Add Specification
                                </button>
                            </div>
                        </div>
                    ))}

                    <button 
                        onClick={addSectionToTemplate}
                        className="w-full border-4 border-dashed border-slate-200 rounded-3xl p-8 text-slate-400 hover:border-indigo-400 hover:text-indigo-600 hover:bg-white transition-all flex flex-col items-center justify-center gap-3 group"
                    >
                        <LayoutPanelTop size={48} className="opacity-20 group-hover:opacity-100 group-hover:scale-110 transition-transform"/>
                        <span className="font-black uppercase tracking-widest text-sm">Add New Technical Section</span>
                    </button>
                </div>

                <div className="p-8 border-t bg-slate-50 flex justify-end gap-4">
                    <button onClick={() => setIsFormatEditorOpen(false)} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs">Discard Changes</button>
                    <button onClick={handleSaveTemplate} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">{isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Synchronizing Database...</> : <><Save size={20}/> Save Global Template</>}</button>
                </div>
            </div>
        </div>
      )}

      {isEditorOpen && editingStyle && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingStyle.id ? 'Edit Master Style' : 'New Master Style Entry'}</h3>
                <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-1">Populating manufacturing technical standard</p>
              </div>
              <div className="flex items-center gap-4">
                <button onClick={() => setIsCopying(!isCopying)} className="bg-indigo-50 text-indigo-600 border border-indigo-200 px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-2 hover:bg-indigo-100 transition-all"><Copy size={20}/> {isCopying ? 'Cancel Cloning' : 'Clone Specifications'}</button>
                <button onClick={() => setIsEditorOpen(false)} className="text-slate-300 hover:text-slate-600 transition-colors p-2 hover:bg-slate-100 rounded-full"><X size={40}/></button>
              </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
               {isCopying && (
                 <div className="w-80 border-r border-slate-200 bg-slate-50 p-6 overflow-y-auto animate-fade-in shrink-0">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6">Select Template Source</h4>
                    <div className="space-y-3">
                       {styles.map(s => (<button key={s.id} onClick={() => handleCopyFrom(s)} className="w-full text-left p-4 bg-white rounded-2xl border border-slate-200 hover:border-indigo-500 hover:shadow-lg transition-all group"><div className="font-black text-lg text-slate-700 group-hover:text-indigo-600">{s.style_no}</div><div className="text-[10px] font-bold text-slate-400">{s.category} • {s.product_type}</div></button>))}
                    </div>
                 </div>
               )}

               <div className="flex-1 overflow-y-auto p-10 space-y-12">
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-6 bg-slate-50 p-8 rounded-[30px] border border-slate-200 shadow-inner">
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Style Reference No.</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 text-xl font-black focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" value={editingStyle.style_no} onChange={e => setEditingStyle({...editingStyle, style_no: e.target.value})}/></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Description Text</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" value={editingStyle.style_text} onChange={e => setEditingStyle({...editingStyle, style_text: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.category} onChange={e => setEditingStyle({...editingStyle, category: e.target.value as any})}><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Audience</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.target_audience} onChange={e => setEditingStyle({...editingStyle, target_audience: e.target.value as any})}><option value="Men">Men</option><option value="Boys">Boys</option></select></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex justify-between">Product Type <button onClick={() => setShowNewTypeInput(!showNewTypeInput)} className="text-indigo-600 hover:underline">{showNewTypeInput ? 'Standard' : 'Custom'}</button></label>{showNewTypeInput ? (<input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={customProductType} onChange={e => setCustomProductType(e.target.value)}/>) : (<select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.product_type} onChange={e => setEditingStyle({...editingStyle, product_type: e.target.value})}>{COMMON_PRODUCT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}</select>)}</div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Packing</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.packing_type} onChange={e => setEditingStyle({...editingStyle, packing_type: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Pcs / Box</label><input type="number" className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.pcs_per_box} onChange={e => setEditingStyle({...editingStyle, pcs_per_box: parseInt(e.target.value) || 1})}/></div>
                  </div>

                  <div className="space-y-16">
                    {template.map(sec => (
                         <div key={sec.section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3"><h4 className="text-xl font-black text-slate-800 uppercase tracking-tight">{sec.section}</h4></div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {template.find(t => t.section === sec.section)?.labels.map((label, lIdx) => {
                                 const globalIdx = details.findIndex(gd => gd.section === sec.section && gd.label === label);
                                 const d = details[globalIdx];
                                 const isTable = sec.is_table_flags?.[lIdx];

                                 return (
                                   <div key={label} className="group bg-slate-50/50 p-6 rounded-[30px] border border-transparent hover:border-indigo-100 hover:bg-white transition-all space-y-4">
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center justify-between">
                                        {label}
                                        {isTable && <TableIcon size={14} className="opacity-50"/>}
                                      </div>

                                      {isTable ? (
                                        <div className="space-y-2">
                                          {(() => {
                                            let tableData: string[][] = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) { }
                                            return tableData.map((row, rowIdx) => (
                                              <div key={rowIdx} className="flex gap-2 animate-fade-in">
                                                <input className="w-1/3 border border-slate-200 rounded-xl p-3 text-xs font-bold bg-white" placeholder="Key" value={row[0]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][0] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <input className="flex-1 border border-slate-200 rounded-xl p-3 text-xs bg-white" placeholder="Value" value={row[1]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][1] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <button onClick={() => {
                                                  if (tableData.length === 1) return;
                                                  const newTable = tableData.filter((_, i) => i !== rowIdx);
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }} className="p-2 text-slate-300 hover:text-red-500"><X size={14}/></button>
                                              </div>
                                            ));
                                          })()}
                                          <button onClick={() => {
                                            let tableData = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) {}
                                            const updated = [...details];
                                            updated[globalIdx].content_text = JSON.stringify([...tableData, ['', '']]);
                                            setDetails(updated);
                                          }} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100">+ Add Row Entry</button>
                                        </div>
                                      ) : (
                                        <textarea className="w-full border-2 border-slate-100 rounded-3xl p-6 text-sm h-32 bg-white text-slate-800 font-medium focus:border-indigo-400 outline-none transition-all resize-none shadow-inner" placeholder={`Provide technical specifications for ${label}...`} value={d.content_text} onChange={e => { const updated = [...details]; updated[globalIdx].content_text = e.target.value; setDetails(updated); }}/>
                                      )}

                                      <div className="flex gap-2 flex-wrap pt-2">
                                        {d.attachments.map((a, aIdx) => (
                                            <div key={aIdx} className="group/att relative w-16 h-16 rounded-2xl border border-slate-200 bg-white flex items-center justify-center shadow-sm overflow-hidden">
                                                {a.type === 'image' ? <img src={a.url} className="w-full h-full object-cover"/> : <FileText size={24} className="text-slate-400"/>}
                                                <button onClick={() => { const updated = [...details]; updated[globalIdx].attachments.splice(aIdx, 1); setDetails(updated); }} className="absolute inset-0 bg-red-600/80 text-white opacity-0 group-hover/att:opacity-100 flex items-center justify-center transition-opacity"><Trash2 size={20}/></button>
                                            </div>
                                        ))}
                                        <label className="w-16 h-16 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-400 cursor-pointer transition-all">
                                            <Upload size={20}/><input type="file" multiple className="hidden" onChange={e => handleFileUpload(e, globalIdx)}/>
                                        </label>
                                      </div>
                                   </div>);
                               })}
                            </div>
                         </div>
                    ))}
                  </div>
               </div>
            </div>

            <div className="p-8 border-t bg-slate-50 flex justify-end gap-4 shadow-[0_-10px_20px_rgba(0,0,0,0.03)]">
               <button onClick={() => setIsEditorOpen(false)} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs">Discard</button>
               <button onClick={handleSave} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">{isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Transmitting...</> : <><Save size={20}/> Save Master Style</>}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment, fetchStyleTemplate, saveStyleTemplate, checkTemplateDeletionImpact, purgeDeletedLabels, deleteTemplateSection } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment, StyleTemplate } from '../types';
import { 
  Library, Search, Plus, Trash2, Copy, Printer, ChevronDown, ChevronRight, X, Upload, FileText, Image as ImageIcon, Save, Loader2, Split, Grid2X2, AlertCircle, Download, MoreVertical, Layers, Users, Settings2, GripVertical, Table as TableIcon, List as ListIcon, LayoutPanelTop
} from 'lucide-react';

const COMMON_PRODUCT_TYPES = ['T-shirt', 'Pant', 'Shorts', 'Shirt', 'Innerwear', 'Sweatshirt', 'Hoodie'];

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [template, setTemplate] = useState<StyleTemplate[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal States
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isFormatEditorOpen, setIsFormatEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  // Format Editor Local State
  const [localTemplate, setLocalTemplate] = useState<StyleTemplate[]>([]);

  // Custom Product Type handling
  const [showNewTypeInput, setShowNewTypeInput] = useState(false);
  const [customProductType, setCustomProductType] = useState('');

  const loadData = async () => {
    setLoading(true);
    try {
        const [libData, tempData] = await Promise.all([
            fetchStyleLibrary(),
            fetchStyleTemplate()
        ]);
        // COMPLETELY ISOLATE 'General Info' from dynamic template logic
        const filteredTemplate = tempData.filter(t => t.section !== 'General Info');
        setStyles(libData);
        setTemplate(filteredTemplate);
    } catch (e) {
        console.error("Style Database Load Failed:", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const prepareDetailsForStyle = (styleDetails: StyleDetail[] = []) => {
      const merged: StyleDetail[] = [];
      template.forEach(t => {
          t.labels.forEach((label, idx) => {
              const existing = styleDetails.find(d => d.section === t.section && d.label === label);
              const isTable = t.is_table_flags?.[idx] || false;

              let content = existing?.content_text || '';
              if (isTable && (!content || content === '')) {
                  content = JSON.stringify([['', '']]);
              }

              merged.push(existing || { section: t.section, label, content_text: content, attachments: [] });
          });
      });
      return merged;
  };

  const handleOpenCreate = () => {
    setEditingStyle({ 
        style_no: '', style_text: '', category: 'Casuals', product_type: 'T-shirt', target_audience: 'Men', pcs_per_box: 1, packing_type: 'cover' 
    });
    setDetails(prepareDetailsForStyle([]));
    setIsEditorOpen(true);
    setShowNewTypeInput(false);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(prepareDetailsForStyle(style.details));
    setIsEditorOpen(true);
    setShowNewTypeInput(!COMMON_PRODUCT_TYPES.includes(style.product_type));
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d, id: undefined, style_id: undefined
    })) || [];
    setDetails(prepareDetailsForStyle(copiedDetails));
    setIsCopying(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const updated = [...details];
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name, url, type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    try {
        const finalStyle = { ...editingStyle, product_type: showNewTypeInput ? customProductType : editingStyle.product_type };
        const result = await upsertStyle(finalStyle, details);
        if (result.error) alert(`Save failed: ${result.error}`);
        else { setIsEditorOpen(false); await loadData(); }
    } catch(e: any) {
        alert(`Error: ${e.message}`);
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleDelete = async (styleId: string) => {
    if (!styleId) return;
    if (!confirm("Are you sure you want to remove this style from the library? This will set it to deleted and hide it from the active database.")) return;

    setLoading(true);
    try {
        const result = await deleteStyle(styleId);
        if (result.success) {
            await loadData();
            setExpandedStyles(prev => prev.filter(id => id !== styleId));
        } else {
            alert(`Could not delete style: ${result.error}`);
        }
    } catch (e: any) {
        alert(`Deletion Error: ${e.message}`);
    } finally {
        setLoading(false);
    }
  };

  // --- FORMAT EDITOR LOGIC ---
  const handleOpenFormatEditor = () => {
      setLocalTemplate(JSON.parse(JSON.stringify(template)));
      setIsFormatEditorOpen(true);
  };

  const addSectionToTemplate = () => {
      const name = prompt("Enter Section Name (e.g., Fabric Specifications):");
      if (!name) return;
      if (localTemplate.some(t => t.section === name)) return alert("Section already exists.");
      setLocalTemplate([...localTemplate, { id: Date.now().toString(), section: name, labels: [], is_table_flags: [], display_order: localTemplate.length + 1 }]);
  };

  const removeSectionFromTemplate = async (sIdx: number) => {
      const section = localTemplate[sIdx].section;
      if (!confirm(`Delete ENTIRE section "${section}"? This will remove all its fields from all styles upon save.`)) return;

      const updated = [...localTemplate];
      updated.splice(sIdx, 1);
      setLocalTemplate(updated);
  };

  const addLabelToTemplate = (sectionIndex: number) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels.push('New Specification Field');
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      } else {
          updated[sectionIndex].is_table_flags.push(false);
      }
      setLocalTemplate(updated);
  };

  const updateLabelInTemplate = (sectionIndex: number, labelIndex: number, val: string) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels[labelIndex] = val;
      setLocalTemplate(updated);
  };

  const toggleTableFlag = (sectionIndex: number, labelIndex: number) => {
      const updated = [...localTemplate];
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      }
      updated[sectionIndex].is_table_flags[labelIndex] = !updated[sectionIndex].is_table_flags[labelIndex];
      setLocalTemplate(updated);
  };

  const removeLabelFromTemplate = (sectionIndex: number, labelIndex: number) => {
      const label = localTemplate[sectionIndex].labels[labelIndex];
      if (!confirm(`Remove field "${label}"? This is permanent.`)) return;
      const updated = [...localTemplate];
      updated[sectionIndex].labels.splice(labelIndex, 1);
      if (updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags.splice(labelIndex, 1);
      }
      setLocalTemplate(updated);
  };

  const handleSaveTemplate = async () => {
      setIsSubmitting(true);
      try {
          const originalSections = template.map(t => t.section);
          const currentSections = localTemplate.map(t => t.section);
          const removedSections = originalSections.filter(s => !currentSections.includes(s));

          for (const rs of removedSections) {
              await deleteTemplateSection(rs);
          }

          for (const section of localTemplate) {
              const oldSection = template.find(t => t.section === section.section);
              if (oldSection) {
                  const deletedLabels = oldSection.labels.filter(l => !section.labels.includes(l));
                  if (deletedLabels.length > 0) {
                      const impact = await checkTemplateDeletionImpact(section.section, section.labels);
                      if (impact.length > 0) {
                          const confirmDelete = confirm(`WARNING: Removing fields in "${section.section}" will delete data for styles:\n\n${impact.join('\n')}\n\nContinue?`);
                          if (!confirmDelete) { setIsSubmitting(false); return; }
                          await purgeDeletedLabels(section.section, section.labels);
                      }
                  }
              }
          }

          const result = await saveStyleTemplate(localTemplate);
          if (!result.success) {
            alert(`Template Save Error: ${result.error}`);
          } else {
            setIsFormatEditorOpen(false);
            await loadData();
          }
      } catch (e: any) {
          alert(`Template Save Exception: ${e.message}`);
      } finally {
          setIsSubmitting(false);
      }
  };

  const renderContent = (content: string, isTable: boolean) => {
