              return (
                <table className="w-full text-xs mt-2 border border-slate-100">
                    <tbody className="divide-y divide-slate-100">
                        {data.map((row, idx) => (
                            <tr key={idx} className="divide-x divide-slate-100">
                                <td className="p-1 font-bold bg-slate-50 w-1/3">{row[0]}</td>
                                <td className="p-1">{row[1]}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
              );
          } catch(e) { return <span className="italic text-red-400 text-[10px]">Empty or Invalid Table Data</span>; }
      }
      return <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{content || '---'}</div>;
  };

